using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Cosmos DB indexing is managed via the container's indexing policy, not EF Core.
        // HasIndex was removed — it now throws InvalidOperationException on the Cosmos provider.

        modelBuilder.Entity<Blog>(entity =>
        {
            // Preserve the EF Core 8 discriminator property name ("Discriminator")
            // so existing documents with c.Discriminator = 'Blog' remain readable.
            entity.HasDiscriminator<string>("Discriminator");

            // Preserve the EF Core 8 compound id format ("Blog|1")
            // so existing documents are still addressable by their original ids.
            entity.HasRootDiscriminatorInJsonId(true);
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

